      "path": "src/server.js",
      "content": "const http = require('http');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const PORT = 3000;
const DATA_FILE = path.join(__dirname, 'data.json');

function loadTodos() {
  try {
    return JSON.parse(fs.readFileSync(DATA_FILE, 'utf8')) || [];
  } catch (err) {
    return [];
  }
}

function saveTodos(todos) {
  fs.writeFileSync(DATA_FILE, JSON.stringify(todos, null, 2));
}

function createTodo(title) {
  const id = crypto.randomBytes(16).toString('hex');
  const createdAt = new Date().toISOString();
  const todo = { id, title, done: false, createdAt };
  const todos = loadTodos();
  todos.push(todo);
  saveTodos(todos);
  return todo;
}

function getTodos() {
  return loadTodos();
}

function getTodoById(id) {
  const todos = loadTodos();
  return todos.find(todo => todo.id === id);
}

function updateTodo(id, done) {
  const todos = loadTodos();
  const todo = todos.find(todo => todo.id === id);
  if (todo) {
    todo.done = done;
    if (done) {
      todo.doneAt = new Date().toISOString();
    } else {
      delete todo.doneAt;
    }
    saveTodos(todos);
  }
  return todo;
}

function deleteTodo(id) {
  const todos = loadTodos();
  const index = todos.findIndex(todo => todo.id === id);
  if (index !== -1) {
    todos.splice(index, 1);
    saveTodos(todos);
  }
}

const server = http.createServer((req, res) => {
  const { method, url } = req;

  if (url === '/health' && method === 'GET') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true }));
  } else if (url === '/openapi.json' && method === 'GET') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(fs.readFileSync(path.join(__dirname, '../openapi.json'), 'utf8'));
  } else if (url === '/todos' && method === 'GET') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true, todos: getTodos() }));
  } else if (url === '/todos' && method === 'POST') {
    let body = '';
    req.on('data', chunk => {
      body += chunk.toString();
    });
    req.on('end', () => {
      const { title } = JSON.parse(body);
      const todo = createTodo(title);
      res.writeHead(201, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: true, todo }));
    });
  } else if (url.startsWith('/todos/') && method === 'GET') {
    const id = url.split('/').pop();
    const todo = getTodoById(id);
    if (todo) {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: true, todo }));
    } else {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: false, error: 'TODO item not found' }));
    }
  } else if (url.startsWith('/todos/') && method === 'PATCH') {
    let body = '';
    req.on('data', chunk => {
      body += chunk.toString();
    });
    req.on('end', () => {
      const id = url.split('/').pop();
      const { done } = JSON.parse(body);
      const todo = updateTodo(id, done);
      if (todo) {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todo }));
      } else {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: false, error: 'TODO item not found' }));
      }
    });
  } else if (url.startsWith('/todos/') && method === 'DELETE') {
    const id = url.split('/').pop();
    deleteTodo(id);
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: true }));
  } else {
    res.writeHead(404, { 'Content-Type': 'text/plain' });
    res.end('Not Found');
  }
});

server.listen(PORT, () => {
  console.log(`Server is running on http://localhost:${PORT}`);
});"
